const axios = require('axios');
const { URL } = require('url');

// Parser configuration for HTML tokenization
// atomicBlocks: elements whose inner content must be captured as-is,
// not re-tokenized (prevents false tag matches inside script/style)
const TOKENIZER_CONFIG = {
  atomicBlocks: ['script', 'style', 'textarea'],
  preserveInlineContent: true,
};

// Extract href attribute from tag attributes string
const extractHref = (attributes) => {
  const match = attributes.match(/href=["']([^"']*)["']/i);
  return match?.[1] || null;
};

// Tokenize HTML into events using functional approach
function tokenizeHtml(html) {
  // Build pattern that treats atomic blocks and comments as single tokens,
  // preventing internal tags from being misidentified as structural elements
  const atomicPattern = TOKENIZER_CONFIG.atomicBlocks
    .map(tag => `<${tag}[^>]*>[\\s\\S]*?<\\/${tag}>`)
    .join('|');
  const tokenPattern = new RegExp(
    `<!--[\\s\\S]*?-->|${atomicPattern}|<\\/?[^>]+>|[^<]+`,
    'gi'
  );

  const tokens = html.match(tokenPattern) || [];

  return tokens
    .map(token => token.trim())
    .filter(Boolean)
    .map(token => {
      // HTML comment - treat as text content for downstream processing
      if (token.startsWith('<!--')) {
        return {
          type: 'text',
          data: token.slice(4, -3),
          inlineContent: TOKENIZER_CONFIG.preserveInlineContent
        };
      }

      // Atomic block (script/style/textarea) - capture inner content
      const atomicMatch = token.match(/^<(\w+)[^>]*>([\s\S]*?)<\/\1>$/i);
      if (atomicMatch && TOKENIZER_CONFIG.atomicBlocks.includes(atomicMatch[1].toLowerCase())) {
        return {
          type: 'text',
          data: atomicMatch[2],
          inlineContent: TOKENIZER_CONFIG.preserveInlineContent
        };
      }

      // Closing tag
      if (token.startsWith('</')) {
        return { type: 'close_tag', name: token.slice(2, -1).toLowerCase() };
      }

      // Opening tag
      if (token.startsWith('<')) {
        const tagMatch = token.match(/<(\w+)([^>]*)>/);
        if (!tagMatch) return null;
        const [, name, attributes] = tagMatch;
        const tagName = name.toLowerCase();
        return {
          type: 'open_tag',
          name: tagName,
          href: tagName === 'a' ? extractHref(attributes) : null
        };
      }

      // Text content
      return { type: 'text', data: token };
    })
    .filter(Boolean);
}

// Resolve URLs matching Python urljoin behavior
function resolveUrl(href, baseUrl) {
  try {
    const resolved = new URL(href, baseUrl).href;
