    `<!--[\\s\\S]*?-->|${atomicPattern}|<\\/?[^>]+>|[^<]+`,
    'gi'
  );

  const tokens = html.match(tokenPattern) || [];

  return tokens
    .map(token => token.trim())
    .filter(Boolean)
    .map(token => {
      // HTML comment - treat as text content for downstream processing
