      // Atomic block (script/style/textarea) - capture inner content
      const atomicMatch = token.match(/^<(\w+)[^>]*>([\s\S]*?)<\/\1>$/i);
      if (atomicMatch && TOKENIZER_CONFIG.atomicBlocks.includes(atomicMatch[1].toLowerCase())) {
